/**
 * FINIFY AI — CYBER THEME TOKENS
 * Supports Dark (default) & Light modes
 */

export const darkTheme = {
  /* -------- Accent (Shared) -------- */
  '--accent-primary': '#9d5ae5',
  '--accent-secondary': '#7a3cc2',
  '--accent-glow': 'rgba(157, 90, 229, 0.35)',

  /* -------- Dark Theme Surface -------- */
  '--bg-main': '#050505',
  '--bg-secondary': '#0b0512',
  '--surface-glass': 'rgba(20, 20, 25, 0.72)',
  '--surface-border': 'rgba(255, 255, 255, 0.12)',

  /* -------- Typography -------- */
  '--text-primary': '#ffffff',
  '--text-secondary': 'rgba(255, 255, 255, 0.7)',
  '--text-muted': 'rgba(255, 255, 255, 0.35)',

  /* -------- Infrastructure -------- */
  '--input-bg': 'rgba(255, 255, 255, 0.04)',
  '--input-border': 'rgba(255, 255, 255, 0.14)',
  '--shadow-elevated': '0 0 45px rgba(0, 0, 0, 0.6)',
};

export const lightTheme = {
  /* -------- Accent (Shared) -------- */
  '--accent-primary': '#9d5ae5',
  '--accent-secondary': '#7a3cc2',
  '--accent-glow': 'rgba(157, 90, 229, 0.15)',

  /* -------- Light Theme Surface -------- */
  '--bg-main': '#f6f7fb',
  '--bg-secondary': '#ebe9f5',
  '--surface-glass': 'rgba(255, 255, 255, 0.85)',
  '--surface-border': 'rgba(157, 90, 229, 0.18)',

  /* -------- Typography -------- */
  '--text-primary': '#1f2937',
  '--text-secondary': '#4b5563',
  '--text-muted': '#6b7280',

  /* -------- Infrastructure -------- */
  '--input-bg': 'rgba(255, 255, 255, 0.9)',
  '--input-border': 'rgba(157, 90, 229, 0.25)',
  '--shadow-elevated': '0 20px 50px rgba(157, 90, 229, 0.15)',
};
